SELECT stat_date AS statDate, project_id AS projectId, merchant_id AS merchantId, contract_id AS contractId, SUM(within_30) AS within30, SUM(days_31_60) AS days3160, SUM(days_61_90) AS days6190, SUM(days_91_180) AS days91180, SUM(days_181_365) AS days181365, SUM(over_365) AS over365, SUM(total_outstanding) AS totalOutstanding FROM rpt_aging_analysis WHERE is_deleted = 0 AND fee_item_id = 0 AND merchant_id != 0 AND contract_id = 0 AND stat_date = #{statDate}
AND merchant_id = #{merchantId}
GROUP BY stat_date, project_id, merchant_id, contract_id ORDER BY totalOutstanding DESC
